// Minimal htmx-like: handles hx-get, hx-post, hx-target, hx-swap, hx-trigger
(function() {
    'use strict';

    function doRequest(el) {
        var method = el.hasAttribute('hx-get') ? 'GET' : 'POST';
        var url    = el.getAttribute('hx-' + method.toLowerCase());
        var sel    = el.getAttribute('hx-target') || '#content';
        var swap   = el.getAttribute('hx-swap')   || 'innerHTML';
        var target = document.querySelector(sel);
        if (!url || !target) return;

        target.setAttribute('aria-busy', 'true');
        fetch(url, { method: method, headers: { 'X-Requested-With': 'htmx' } })
            .then(function(r) { return r.text(); })
            .then(function(html) {
                if (swap === 'outerHTML') {
                    target.outerHTML = html;
                } else if (swap === 'beforeend') {
                    target.insertAdjacentHTML('beforeend', html);
                } else {
                    target.innerHTML = html;
                }
                target.removeAttribute('aria-busy');
            })
            .catch(function(err) {
                target.innerHTML = '<span style="color:#f85149">Error: ' + err.message + '</span>';
                target.removeAttribute('aria-busy');
            });
    }

    document.addEventListener('DOMContentLoaded', function() {
        // click delegation
        document.body.addEventListener('click', function(e) {
            var el = e.target.closest('[hx-get],[hx-post]');
            if (!el) return;
            var trigger = el.getAttribute('hx-trigger') || 'click';
            if (trigger !== 'click') return;
            e.preventDefault();
            doRequest(el);
        });

        // change delegation (for selects / inputs with hx-trigger="change")
        document.body.addEventListener('change', function(e) {
            var el = e.target.closest('[hx-get],[hx-post]');
            if (!el) return;
            if (el.getAttribute('hx-trigger') !== 'change') return;
            doRequest(el);
        });
    });
})();
